// initials — 1-2 заглавные буквы для аватара из email (до "@").
func initials(email string) string {
	local := email
	if i := strings.IndexByte(email, '@'); i > 0 {
		local = email[:i]
	}
	local = strings.TrimSpace(local)
	if local == "" {
		return ""
	}
	r := []rune(local)
	if len(r) == 1 {
		return strings.ToUpper(string(r[0:1]))
	}
	return strings.ToUpper(string(r[0:2]))
}

// itoa — форматирование int64 для построения href-ов в шаблонах.
func itoa(n int64) string {
	return strconv.FormatInt(n, 10)
}

// currentProjectName — имя проекта в переключателе: текущий проект по
// ProjectID, иначе первый из списка, иначе пусто.
func currentProjectName(s nav.Shell) string {
	for _, p := range s.Projects {
		if p.ID == s.ProjectID {
			return p.Name
		}
	}
	if len(s.Projects) > 0 {
		return s.Projects[0].Name
	}
	return ""
}

// effectiveProjectID — ProjectID, если задан, иначе ID первого проекта,
// иначе 0.
func effectiveProjectID(s nav.Shell) int64 {
	if s.ProjectID != 0 {
		return s.ProjectID
	}
	if len(s.Projects) > 0 {
		return s.Projects[0].ID
	}
	return 0
}

